/**
 * ===========================================
 * AttachmentGallery
 * ===========================================
 *
 * Image lightbox, file data preview (CSV/JSON),
 * HTML iframe preview, tab filtering,
 * and attachment tagging popover.
 *
 * @usage HTML (generated by AttachmentGallery.php)
 *   <div data-attachment-gallery data-project="slug">
 *     <button data-attachment-tab data-tab="images">Images</button>
 *     <div data-attachment-section data-type="images">
 *       <div data-image-card data-src="..." data-name="...">...</div>
 *     </div>
 *     <button data-file-toggle data-file="..." data-type="csv" data-project="...">View</button>
 *     <div data-file-preview class="hidden"></div>
 *     <button data-iframe-toggle data-src="...">Preview</button>
 *     <div data-iframe-preview class="hidden"><iframe></iframe></div>
 *     <button data-tag-attachment data-attachment="...">Tag</button>
 *   </div>
 *   <div data-attachment-lightbox class="hidden">
 *     <button data-lightbox-close>...</button>
 *     <button data-lightbox-prev>...</button>
 *     <button data-lightbox-next>...</button>
 *     <div data-lightbox-content><img></div>
 *     <div data-lightbox-caption></div>
 *   </div>
 *   <div data-tag-popover style="display:none">
 *     <button data-close-tag-popover>x</button>
 *     <div data-tag-popover-content></div>
 *   </div>
 */

const AttachmentGallery = (function () {
    'use strict';

    // -- Private: Config --
    const CONFIG = {
        debug: false,
        eventNamespace: '.attachmentGallery',
    };

    // -- Private: Selectors --
    const SELECTORS = {
        gallery: '[data-attachment-gallery]',
        tab: '[data-attachment-tab]',
        section: '[data-attachment-section]',
        imageCard: '[data-image-card]',
        fileToggle: '[data-file-toggle]',
        filePreview: '[data-file-preview]',
        iframeToggle: '[data-iframe-toggle]',
        iframePreview: '[data-iframe-preview]',
        tagBtn: '[data-tag-attachment]',
        removeTag: '[data-remove-tag]',
        taggedAttachment: '[data-tagged-attachment]',
        lightbox: '[data-attachment-lightbox]',
        lightboxClose: '[data-lightbox-close]',
        lightboxPrev: '[data-lightbox-prev]',
        lightboxNext: '[data-lightbox-next]',
        lightboxContent: '[data-lightbox-content]',
        lightboxCaption: '[data-lightbox-caption]',
        tagPopover: '[data-tag-popover]',
        tagPopoverContent: '[data-tag-popover-content]',
        closeTagPopover: '[data-close-tag-popover]',
    };

    // -- Private: State --
    let state = {
        initialized: false,
        images: [],
        currentIndex: 0,
    };

    // -- Private: Cached DOM --
    let $lightbox = null;

    // -- Private: Utils --
    function log(...args) {
        if (CONFIG.debug) console.log('[AttachmentGallery]', ...args);
    }

    function setState(newState) {
        state = Object.assign({}, state, newState);
    }

    function escapeHtml(text) {
        var div = document.createElement('div');
        div.textContent = String(text);
        return div.innerHTML;
    }

    // -- Private: Setup --
    function cacheDom() {
        $lightbox = window.jQuery(SELECTORS.lightbox);
    }

    function setup() {
        cacheDom();
        return window.jQuery(SELECTORS.gallery).length > 0;
    }

    function collectImages() {
        var images = [];
        window.jQuery(SELECTORS.imageCard).each(function () {
            var $card = window.jQuery(this);
            images.push({ src: $card.attr('data-src'), name: $card.attr('data-name') });
        });
        setState({ images: images });
    }

    // -- Private: Lightbox --
    function openLightbox(index) {
        if (!$lightbox.length || state.images.length === 0) return;
        setState({ currentIndex: index });
        updateLightboxImage();
        $lightbox.removeClass('hidden');
        document.body.style.overflow = 'hidden';
    }

    function closeLightbox() {
        if (!$lightbox.length) return;
        $lightbox.addClass('hidden');
        document.body.style.overflow = '';
    }

    function prevImage() {
        setState({ currentIndex: (state.currentIndex - 1 + state.images.length) % state.images.length });
        updateLightboxImage();
    }

    function nextImage() {
        setState({ currentIndex: (state.currentIndex + 1) % state.images.length });
        updateLightboxImage();
    }

    function updateLightboxImage() {
        var img = state.images[state.currentIndex];
        if (!img) return;
        var $img = $lightbox.find(SELECTORS.lightboxContent + ' img');
        var $caption = $lightbox.find(SELECTORS.lightboxCaption);
        $img.attr('src', img.src).attr('alt', img.name);
        $caption.text(img.name + ' (' + (state.currentIndex + 1) + ' / ' + state.images.length + ')');
    }

    // -- Private: Data Files --
    function loadDataFile(project, file, type, $container) {
        $container.html('<div class="text-center py-4"><span class="text-gray-500">Loading...</span></div>');

        var url = 'index.php?action=attachment-data'
            + '&project=' + encodeURIComponent(project)
            + '&file=' + encodeURIComponent(file)
            + '&type=' + encodeURIComponent(type);

        fetch(url)
            .then(function (r) { return r.json(); })
            .then(function (data) {
                if (data.error) {
                    $container.html('<div class="text-red-500 p-4">' + escapeHtml(data.error) + '</div>');
                    return;
                }
                if (type === 'csv') {
                    $container.html(renderCsvTable(data));
                } else if (type === 'json') {
                    $container.html(renderJsonView(data));
                }
            })
            .catch(function (err) {
                $container.html('<div class="text-red-500 p-4">Error loading file: ' + escapeHtml(err.message) + '</div>');
            });
    }

    function renderCsvTable(data) {
        if (!data.headers || !data.data) return '<div class="text-gray-500">No data</div>';
        var html = '<div class="overflow-x-auto"><table class="w-full text-sm">';
        html += '<thead><tr class="bg-gray-200 dark:bg-gray-700">';
        data.headers.forEach(function (h) {
            html += '<th class="px-3 py-2 text-left font-medium text-gray-700 dark:text-gray-200">' + escapeHtml(h) + '</th>';
        });
        html += '</tr></thead><tbody>';
        data.data.forEach(function (row, i) {
            var bg = i % 2 === 0 ? 'bg-white dark:bg-gray-800' : 'bg-gray-50 dark:bg-gray-750';
            html += '<tr class="' + bg + '">';
            data.headers.forEach(function (h) {
                html += '<td class="px-3 py-2 border-b border-gray-200 dark:border-gray-700 text-gray-600 dark:text-gray-300">' + escapeHtml(row[h] || '') + '</td>';
            });
            html += '</tr>';
        });
        html += '</tbody></table></div>';
        html += '<div class="mt-2 text-sm text-gray-500 dark:text-gray-400">' + data.rowCount + ' rows</div>';
        return html;
    }

    function renderJsonView(data) {
        var formatted = data.formatted || JSON.stringify(data.data, null, 2);
        return '<pre class="bg-gray-900 text-gray-100 p-4 rounded-lg overflow-auto text-sm" style="max-height:400px;"><code class="language-json text-gray-100">'
            + escapeHtml(formatted) + '</code></pre>';
    }

    // -- Private: Tag Popover --
    function openTagPopover($btn) {
        const $ = window.jQuery;
        var $popover = $(SELECTORS.tagPopover);
        var $content = $(SELECTORS.tagPopoverContent);
        if (!$popover.length || !$content.length) return;

        var $card = $btn.closest('[data-attachment-card], [data-image-card], [data-file-card], [data-web-card]');
        if (!$card.length) $card = $btn.parent();

        var rect = $card.get(0).getBoundingClientRect();
        var popoverWidth = 256;
        var top = rect.bottom + 8;
        var left = rect.left + (rect.width / 2) - (popoverWidth / 2);
        if (left < 10) left = 10;
        if (left + popoverWidth > window.innerWidth - 10) left = window.innerWidth - popoverWidth - 10;
        if (top + 200 > window.innerHeight) top = rect.top - 210;

        $popover.css({ top: top + 'px', left: left + 'px', display: 'block' });
        $content.html('<p class="text-gray-500 text-xs">Loading...</p>');

        var project = document.body.dataset.project || '';
        var currentUrl = window.location.origin + window.location.pathname;

        fetch(currentUrl + '?action=attachment-pages&project=' + encodeURIComponent(project))
            .then(function (r) { return r.json(); })
            .then(function (pages) {
                var html = '<form data-tag-form class="space-y-2">';
                html += '<input type="hidden" name="attachment" value="' + escapeHtml($btn.attr('data-attachment')) + '">';
                html += '<div><label class="block text-xs font-medium text-gray-500 dark:text-gray-400 mb-1">Page</label>';
                html += '<select name="page" data-tag-page-select class="w-full p-1.5 text-xs rounded border border-gray-300 dark:border-gray-600 dark:bg-gray-700 dark:text-white">';
                pages.forEach(function (page) {
                    html += '<option value="' + escapeHtml(page.slug) + '" data-sections=\'' + JSON.stringify(page.sections || []) + '\'>' + escapeHtml(page.name) + '</option>';
                });
                html += '</select></div>';
                html += '<div><label class="block text-xs font-medium text-gray-500 dark:text-gray-400 mb-1">Section</label>';
                html += '<select name="section" data-tag-section-select class="w-full p-1.5 text-xs rounded border border-gray-300 dark:border-gray-600 dark:bg-gray-700 dark:text-white">';
                html += '<option value="">-- Optional --</option></select></div>';
                html += '<button type="submit" class="w-full py-1.5 text-xs bg-blue-600 text-white rounded hover:bg-blue-700 transition-colors font-medium">Tag</button>';
                html += '</form>';

                $content.html(html);

                var $pageSelect = $content.find('[data-tag-page-select]');
                var $sectionSelect = $content.find('[data-tag-section-select]');

                function updateSections() {
                    var selected = $pageSelect.get(0).options[$pageSelect.get(0).selectedIndex];
                    var sections = [];
                    try { sections = JSON.parse(selected.dataset.sections || '[]'); } catch (e) { }
                    $sectionSelect.html('<option value="">-- Optional --</option>');
                    sections.forEach(function (sec) {
                        $sectionSelect.get(0).innerHTML += '<option value="' + escapeHtml(sec) + '">' + escapeHtml(sec) + '</option>';
                    });
                }

                $pageSelect.on('change' + CONFIG.eventNamespace, updateSections);
                updateSections();

                $content.find('[data-tag-form]').on('submit' + CONFIG.eventNamespace, function (e) {
                    e.preventDefault();
                    var form = e.target;
                    fetch(currentUrl + '?action=tag-attachment', {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify({
                            attachment: form.attachment.value,
                            page: form.page.value,
                            section: form.section.value,
                        }),
                    })
                        .then(function (r) { return r.json(); })
                        .then(function (resp) {
                            if (resp.success) {
                                $content.html('<p class="text-green-600 text-xs text-center py-2">Tagged!</p>');
                                setTimeout(function () { $(SELECTORS.tagPopover).css('display', 'none'); }, 500);
                            } else {
                                $content.find('button[type="submit"]').after('<p class="text-red-500 text-xs mt-1">Error</p>');
                            }
                        });
                });
            });
    }

    // -- Private: Events --
    function bindEvents() {
        const $ = window.jQuery;
        var ns = CONFIG.eventNamespace;

        // Tabs
        $(document).on('click' + ns, SELECTORS.tab, function () {
            var $btn = $(this);
            var targetTab = $btn.attr('data-tab');

            $(SELECTORS.tab).removeClass('active border-blue-500 text-blue-600 dark:text-blue-400')
                .addClass('border-transparent text-gray-500 dark:text-gray-400');
            $btn.addClass('active border-blue-500 text-blue-600 dark:text-blue-400')
                .removeClass('border-transparent text-gray-500 dark:text-gray-400');

            $(SELECTORS.section).each(function () {
                var $s = $(this);
                if (targetTab === 'all' || $s.attr('data-type') === targetTab) {
                    $s.removeClass('hidden');
                } else {
                    $s.addClass('hidden');
                }
            });
        });

        // Image card lightbox
        $(document).on('click' + ns, SELECTORS.imageCard, function (e) {
            if ($(e.target).closest(SELECTORS.tagBtn).length) return;
            var index = $(SELECTORS.imageCard).index(this);
            openLightbox(index);
        });

        // Lightbox controls
        $lightbox.on('click' + ns, SELECTORS.lightboxClose, closeLightbox);
        $lightbox.on('click' + ns, SELECTORS.lightboxPrev, prevImage);
        $lightbox.on('click' + ns, SELECTORS.lightboxNext, nextImage);
        $lightbox.on('click' + ns, function (e) {
            if ($(e.target).is(SELECTORS.lightbox)) closeLightbox();
        });

        // Keyboard navigation
        $(document).on('keydown' + ns, function (e) {
            if ($lightbox.hasClass('hidden')) return;
            if (e.key === 'Escape') closeLightbox();
            if (e.key === 'ArrowLeft') prevImage();
            if (e.key === 'ArrowRight') nextImage();
        });

        // Data file toggles
        $(document).on('click' + ns, SELECTORS.fileToggle, function () {
            var $btn = $(this);
            var $card = $btn.closest('[data-file-card]');
            var $preview = $card.find(SELECTORS.filePreview);
            if ($preview.hasClass('hidden')) {
                loadDataFile($btn.attr('data-project'), $btn.attr('data-file'), $btn.attr('data-type'), $preview);
                $preview.removeClass('hidden');
                $btn.text('Hide');
            } else {
                $preview.addClass('hidden');
                $btn.text('View');
            }
        });

        // Iframe toggles
        $(document).on('click' + ns, SELECTORS.iframeToggle, function () {
            var $btn = $(this);
            var $card = $btn.closest('[data-web-card]');
            var $preview = $card.find(SELECTORS.iframePreview);
            var $iframe = $preview.find('iframe');
            if ($preview.hasClass('hidden')) {
                $iframe.attr('src', $btn.attr('data-src'));
                $preview.removeClass('hidden');
                $btn.text('Hide');
            } else {
                $iframe.attr('src', '');
                $preview.addClass('hidden');
                $btn.text('Preview');
            }
        });

        // Tag attachment popover
        $(document).on('click' + ns, SELECTORS.tagBtn, function (e) {
            e.preventDefault();
            e.stopPropagation();
            openTagPopover($(this));
        });

        // Close tag popover
        $(document).on('click' + ns, SELECTORS.closeTagPopover, function () {
            $(SELECTORS.tagPopover).css('display', 'none');
        });

        $(document).on('click' + ns, function (e) {
            var $popover = $(SELECTORS.tagPopover);
            if ($popover.length && $popover.css('display') !== 'none') {
                if (!$popover.find(e.target).length && !$(e.target).closest(SELECTORS.tagBtn).length) {
                    $popover.css('display', 'none');
                }
            }
        });

        // Remove tag
        $(document).on('click' + ns, SELECTORS.removeTag, function (e) {
            e.preventDefault();
            e.stopPropagation();
            var $btn = $(this);
            var attachment = $btn.attr('data-attachment');
            var page = $btn.attr('data-page');
            var section = $btn.attr('data-section') || '';
            var $tag = $btn.closest(SELECTORS.taggedAttachment);

            if (!confirm('Remove tag for "' + attachment + '"?')) return;

            var currentUrl = window.location.origin + window.location.pathname;
            fetch(currentUrl + '?action=tag-attachment', {
                method: 'DELETE',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ attachment: attachment, page: page, section: section }),
            })
                .then(function (r) { return r.json(); })
                .then(function (resp) {
                    if (resp.success) {
                        $tag.css({ opacity: '0', transform: 'translateX(20px)' });
                        setTimeout(function () { $tag.get(0).remove(); }, 300);
                    } else {
                        alert('Error removing tag: ' + (resp.error || 'Unknown'));
                    }
                });
        });
    }

    function unbindEvents() {
        const $ = window.jQuery;
        $(document).off(CONFIG.eventNamespace);
        if ($lightbox) $lightbox.off(CONFIG.eventNamespace);
    }

    // -- Public: Init --
    function init() {
        const $ = window.jQuery;
        if (!$) { console.warn('[AttachmentGallery] jQuery not available'); return; }
        if (!setup()) return;
        if (state.initialized) return;

        collectImages();
        bindEvents();

        setState({ initialized: true });
        log('Initialized');
    }

    // -- Public: Destroy --
    function destroy() {
        if (!state.initialized) return;
        unbindEvents();
        setState({ initialized: false, images: [], currentIndex: 0 });
        log('Destroyed');
    }

    // -- Public API --
    return { init: init, destroy: destroy };

})();

export default AttachmentGallery;
